using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketInput
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; }
}

public class TicketResponse
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public static class TicketModelTrainer
{
    public static (ITransformer Model, string MetricsReport) TrainAndEvaluate(string dataPath)
    {
        var mlContext = new MLContext(seed: 42);

        IDataView data = mlContext.Data.LoadFromTextFile<TicketInput>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = mlContext.Transforms.Text
                .FeaturizeText("SubjectFeatures", nameof(TicketInput.Subject))
            .Append(mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketInput.Description)))
            .Append(mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketInput.Priority)))
            .Append(mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketInput.Category)))
            .Append(mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = mlContext.MulticlassClassification.Evaluate(predictions);

        var report = $"""
            ===== Ticket Classifier Metrics =====
            MacroAccuracy:    {metrics.MacroAccuracy:F4}
            MicroAccuracy:    {metrics.MicroAccuracy:F4}
            LogLoss:          {metrics.LogLoss:F4}
            LogLossReduction: {metrics.LogLossReduction:F4}
            =====================================
            """;

        return (model, report);
    }

    public static void SaveModel(MLContext mlContext, ITransformer model,
        DataViewSchema schema, string modelPath)
    {
        mlContext.Model.Save(model, schema, modelPath);
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketsController(
    PredictionEnginePool<TicketInput, TicketPrediction> predictionPool,
    ILogger<TicketsController> logger) : ControllerBase
{
    [HttpPost("classify")]
    public ActionResult<TicketResponse> Classify([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) ||
            string.IsNullOrWhiteSpace(request.Description))
        {
            return BadRequest("Subject and Description are required.");
        }

        if (request.Priority is < 1 or > 3)
        {
            return BadRequest("Priority must be between 1 and 3.");
        }

        var input = new TicketInput
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = predictionPool.Predict(input);

        logger.LogInformation(
            "Classified ticket \"{Subject}\" as {Category}",
            request.Subject, prediction.Category);

        var slotNames = new[] { "Billing", "General", "Technical" };
        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < slotNames.Length; i++)
        {
            confidence[slotNames[i]] = prediction.Score[i];
        }

        return Ok(new TicketResponse
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }
}

